class Solution(object):
    def maxSubarrays(self, nums):
        total_and = nums[0]
        for x in nums:
            total_and &= x

        if total_and != 0:
            return 1

        count = 0
        cur_and = ~0  # all bits set
        for x in nums:
            cur_and &= x
            if cur_and == 0:
                count += 1
                cur_and = ~0  # reset for next subarray
        return count
